+            const metaPos = 36 + i * 16;
+            const typeEnum = view.getUint32(metaPos, true);
+            const nameOff = view.getUint32(metaPos + 4, true);
+            const nameLen = view.getUint32(metaPos + 8, true);
+            const dataOff = view.getUint32(metaPos + 12, true);
+
